module binary_counter_4bit(clk, rst, en, Q);
    input clk, rst, en;
    output reg [3:0] Q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst)
            Q <= 4'b0000;
        else if (en)
            Q <= Q + 1;
    end
endmodule
